前言开发安卓的小伙伴都遇到过APP突然崩溃,无响应的情况.如果发生在自己手中,那么还可以通过IDE查看错误日志,但是实际都是发生在用户手中,那么这个时候产生崩溃,无响应ANR异常就很麻烦.无从下手.因此,需要全局异常捕获.也就是对未知异常,程序员没有处理的异常进行处理,记录等便于分析查找原因，而一个美观的崩溃提示则可以大大加分 。 效果展示效果展示 源码MyUncaughtExceptionHandler. android.content.Context;import android.content.Intent;import android.content.pm.PackageInfo;import android.content.pm.PackageManager;import android.os.Build;import java.io.File;import java.io.FileOutputStream;import java.io.IOException;import java.io.PrintWriter;import java.io.StringWriter;import java.io.Writer;import java.lang.reflect.Field;import java.text.SimpleDateFormat;import java.util.ArrayList;import java.util.Arrays;import java.util.Date;import java.util.Locale;/** * @ClassName MyUncaughtExceptionHandler * @Description 全局捕捉异常 * @Author summerain0 * @Date 2020/9/11 15:31 */public class MyUncaughtExceptionHandler implements Thread.UncaughtExceptionHandler &#123; // 单例 private static MyUncaughtExceptionHandler myUncaughtExceptionHandler; // 上下文 private Context context; // 会输出到文件中 private StringBuilder stringBuilder; // 系统异常处理器 private Thread.UncaughtExceptionHandler defaultUncaughtExceptionHandler; public MyUncaughtExceptionHandler(Context context) &#123; this.context = context; &#125; // 获取单例 public static synchronized MyUncaughtExceptionHandler getInstance(Context ctx) &#123; if (myUncaughtExceptionHandler == null) &#123; myUncaughtExceptionHandler = new MyUncaughtExceptionHandler(ctx); &#125; return myUncaughtExceptionHandler; &#125; // 初始化 public void init() &#123; defaultUncaughtExceptionHandler = Thread.getDefaultUncaughtExceptionHandler(); Thread.setDefaultUncaughtExceptionHandler(this); &#125; @Override public void uncaughtException(Thread thread, Throwable throwable) &#123; if (throwable == null) &#123; defaultUncaughtExceptionHandler.uncaughtException(thread, throwable); &#125; // 创建集合对象 stringBuilder = new StringBuilder(); // 记录时间 SimpleDateFormat simpleDateFormat = new SimpleDateFormat(&quot;yyyy-MM-dd_HH:mm:ss.SSS&quot;, Locale.getDefault()); String date = simpleDateFormat.format(new Date()); addMessage(&quot;崩溃时间&quot;, date); // 记录应用版本信息 try &#123; PackageManager pm = context.getPackageManager(); PackageInfo pi = pm.getPackageInfo(context.getPackageName(), PackageManager.GET_ACTIVITIES); addMessage(&quot;版本名&quot;, pi.versionName); addMessage(&quot;版本号&quot;, pi.versionCode); &#125; catch (PackageManager.NameNotFoundException e) &#123; e.printStackTrace(); addMessage(&quot;error&quot;, &quot;记录版本信息失败！&quot; + e.getMessage()); &#125; // 记录设备信息 Field[] fields = Build.class.getDeclaredFields(); for (Field field : fields) &#123; try &#123; field.setAccessible(true); Object obj = field.get(null); if (obj != null) &#123; addMessage(field.getName(), obj); &#125; &#125; catch (IllegalAccessException e) &#123; e.printStackTrace(); addMessage(&quot;error&quot;, &quot;记录设备信息失败！&quot; + e.getMessage()); &#125; &#125; // 添加分隔符 addMessage(null, &quot;==============================================================&quot;); addMessage(null, &quot;======================== 崩溃日志 =========================&quot;); addMessage(null, &quot;==============================================================&quot;); // 记录崩溃信息 Writer writer = new StringWriter(); PrintWriter printWriter = new PrintWriter(writer); throwable.printStackTrace(printWriter); Throwable cause = throwable.getCause(); while (cause != null) &#123; cause.printStackTrace(printWriter); cause = cause.getCause(); &#125; printWriter.close(); addMessage(null, writer.toString()); // 生成路径，保存至/Android/data/包名，无需读写权限 try &#123; File root = context.getExternalFilesDir(&quot;log&quot;); String filename = date + &quot;.log&quot;; File file = new File(root, filename); FileOutputStream fos = new FileOutputStream(file); fos.write(stringBuilder.toString().getBytes()); fos.close(); &#125; catch (IOException e) &#123; e.printStackTrace(); defaultUncaughtExceptionHandler.uncaughtException(thread, throwable); &#125; // 启动崩溃异常页面 Intent intent = new Intent(context, UncaughtExceptionActivity.class); intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK);// 请勿修改，否则无法打开页面 intent.putExtra(&quot;error&quot;, stringBuilder.toString()); context.startActivity(intent); System.exit(1);// 请勿修改，否则无法打开页面 &#125; // 添加数据 private void addMessage(String key, Object obj) &#123; // 对数组做一下处理 if (obj instanceof String[]) &#123; String[] list = (String[]) obj; ArrayList&lt;String&gt; array = new ArrayList&lt;&gt;(Arrays.asList(list)); stringBuilder.append(key).append(&quot;=&quot;).append(array.toString()).append(&quot;
