&quot;); &#125; &#125;&#125; UncaughtExceptionActivity.java123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657import android.content.Intent;import android.os.Bundle;import android.view.Menu;import android.view.MenuItem;import android.widget.ScrollView;import android.widget.TextView;import android.widget.Toast;import androidx.appcompat.app.AppCompatActivity;/** * @ClassName UncaughtExceptionActivity * @Description 异常页面 * @Author summerain0 * @Date 2020/9/12 11:02 */public class UncaughtExceptionActivity extends AppCompatActivity &#123; public static final String TAG = &quot;UncaughtExceptionActivity&quot;; @Override protected void onCreate(Bundle savedInstanceState) &#123; super.onCreate(savedInstanceState); // 读取日志，显示在屏幕上 String msg = getIntent().getStringExtra(&quot;error&quot;); ScrollView scrollView = new ScrollView(this);// 防止日志太长看不完 scrollView.setLayoutParams(new ScrollView.LayoutParams(ScrollView.LayoutParams.MATCH_PARENT, ScrollView.LayoutParams.MATCH_PARENT)); TextView textView = new TextView(this); textView.setText(msg); scrollView.addView(textView); setContentView(scrollView); &#125; @Override public boolean onCreateOptionsMenu(Menu menu) &#123; menu.add(0, 0, 0, &quot;重启&quot;).setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM); menu.add(0, 1, 0, &quot;上传&quot;).setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM); return super.onCreateOptionsMenu(menu); &#125; @Override public boolean onOptionsItemSelected(MenuItem item) &#123; switch (item.getItemId()) &#123; case 0: Intent intent = new Intent(this, MainActivity.class); intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK);// 请勿修改，否则无法打开页面 startActivity(intent); System.exit(1);// 请勿修改，否则无法打开页面 case 1: // 这里自己写上传逻辑 Toast.makeText(this, &quot;已上传！&quot;, Toast.LENGTH_SHORT).show(); &#125; return true; &#125;&#125; MyApplication.java123456789101112131415161718import android.app.Application;/** * @ClassName MyApplication * @Description TODO * @Author summerain0 * @Date 2020/9/11 14:00 */public class MyApplication extends Application &#123; public static final String TAG = &quot;MyApplication&quot;; @Override public void onCreate() &#123; super.onCreate(); // 初始化异常处理器 MyUncaughtExceptionHandler.getInstance(MyApplication.this).init(); &#125;&#125; AndroidManifest.xml123456789&lt;application android:name=&quot;.MyApplication&quot; ......&gt; &lt;activity android:label=&quot;崩溃异常&quot; android:name=&quot;.UncaughtExceptionActivity&quot; /&gt;&lt;/application&gt;

